// Preparar prompt para Claude con perfil del usuario y ejercicios disponibles
const usuario = $node["Obtener Datos Usuario"].json;
const ejerciciosFuerza = $('Obtener Ejercicios Disponibles').all();
// Cardio: sub-tipos de caminata definidos directamente en el prompt (sin tabla BD)
const ejerciciosCardio = [];

console.log(`📝 Preparando prompt para ${usuario.nombre}`);
console.log(`📊 Ejercicios fuerza: ${ejerciciosFuerza.length}, Ejercicios cardio: ${ejerciciosCardio.length}`);
console.log(`⚙️ Intensidad: ${usuario.intensidad_nivel}%, Volumen extra: ${usuario.volumen_extra}%`);

// Parsear perfil_inicial
const perfil = typeof usuario.perfil_inicial === 'string'
  ? JSON.parse(usuario.perfil_inicial)
  : usuario.perfil_inicial;

const limitaciones = perfil.limitaciones || 'ninguna';
const objetivo = perfil.objetivo_principal || 'general';
const nivelMovilidad = perfil.nivel_movilidad || 'buena';

// FUNCIÓN: Calcular texto de intensidad para el prompt
function calcularTextoIntensidad(intensidad, volumen) {
  if (intensidad < 40) {
    return `
⚠️ INTENSIDAD MUY REDUCIDA (${intensidad}%)
Adapta significativamente:
- Repeticiones: Reduce 30-40% del estándar del nivel
- Series: 2 series en vez de 3
- Descansos: 50% más largos (90 segundos en vez de 60)
- Variaciones: Ejercicios más simples, con apoyo o versiones asistidas
- Progresión: Muy gradual, priorizar técnica correcta`;
  } else if (intensidad >= 40 && intensidad < 60) {
    return `
💡 INTENSIDAD REDUCIDA (${intensidad}%)
Adapta moderadamente:
- Repeticiones: 10-20% menos del estándar
- Series: 2-3 series
- Descansos: Generosos (60-75 segundos)
- Variaciones: Versiones básicas del nivel`;
  } else if (intensidad >= 60 && intensidad <= 75) {
    return `
✅ INTENSIDAD ESTÁNDAR (${intensidad}%)
Programa normal del nivel ${usuario.nivel_actual}:
- Repeticiones: Rango estándar del nivel
- Series: 3 series
- Descansos: Moderados (45-60 segundos)
- Variaciones: Ejercicios base del nivel`;
  } else if (intensidad > 75 && intensidad < 90) {
    return `
🔥 INTENSIDAD ELEVADA (${intensidad}%)
Usuario progresando bien, aumentar desafío:
- Repeticiones: 10-15% más que el estándar
- Series: 3 series completas
- Descansos: Reducidos (30-45 segundos)
- Variaciones: Versiones más desafiantes del nivel`;
  } else {
    // intensidad >= 90
    let texto = `
🚀 INTENSIDAD MÁXIMA (${intensidad}%)
Máximo desafío del nivel ${usuario.nivel_actual}:
- Repeticiones: Rango alto (12-15 reps)
- Series: 3-4 series
- Descansos: Cortos (30 segundos)
- Variaciones: Versiones avanzadas del nivel`;

    if (volumen > 0) {
      texto += `

📈 VOLUMEN EXTRA (+${volumen}%)
El usuario ha dominado la intensidad máxima. Añade volumen:
- Añade 1 serie más a ejercicios principales (4 en vez de 3)
- O aumenta repeticiones proporcionalmente
- O incluye variaciones más complejas (unilaterales, explosivos)
- O reduce descansos aún más (20-30 seg)`;
    }

    return texto;
  }
}

const textoIntensidad = calcularTextoIntensidad(usuario.intensidad_nivel, usuario.volumen_extra);

// MATRIZ SIMPLIFICADA: SOLO FUERZA Y CARDIO
const matrizDistribucion = {
  'movilidad': {
    2: ['fuerza', 'fuerza'],
    3: ['fuerza', 'cardio', 'fuerza'],
    4: ['fuerza', 'cardio', 'fuerza', 'cardio'],
    5: ['fuerza', 'cardio', 'fuerza', 'cardio', 'fuerza']
  },
  'fuerza': {
    2: ['fuerza', 'cardio'],
    3: ['fuerza', 'cardio', 'fuerza'],
    4: ['fuerza', 'cardio', 'fuerza', 'cardio'],
    5: ['fuerza', 'cardio', 'fuerza', 'cardio', 'fuerza']
  },
  'equilibrio': {
    2: ['fuerza', 'fuerza'],
    3: ['fuerza', 'cardio', 'fuerza'],
    4: ['fuerza', 'cardio', 'fuerza', 'cardio'],
    5: ['fuerza', 'cardio', 'fuerza', 'cardio', 'fuerza']
  },
  'cardio': {
    2: ['cardio', 'fuerza'],
    3: ['cardio', 'fuerza', 'cardio'],
    4: ['cardio', 'fuerza', 'cardio', 'fuerza'],
    5: ['cardio', 'fuerza', 'cardio', 'fuerza', 'cardio']
  },
  'general': {
    2: ['fuerza', 'cardio'],
    3: ['fuerza', 'cardio', 'fuerza'],
    4: ['fuerza', 'cardio', 'fuerza', 'cardio'],
    5: ['fuerza', 'cardio', 'fuerza', 'cardio', 'fuerza']
  }
};

// Determinar tipo de sesión
const sesionesSemanales = parseInt(usuario.sesiones_objetivo_semana) || 3;
const numeroSesion = parseInt(usuario.sesion_actual_dentro_semana) || 1;
const objetivoNormalizado = objetivo.toLowerCase();
const objetivoKey = matrizDistribucion[objetivoNormalizado] ? objetivoNormalizado : 'general';
const patron = matrizDistribucion[objetivoKey][sesionesSemanales] || matrizDistribucion['general'][3];
const tipoSesion = patron[numeroSesion - 1] || 'fuerza';

console.log(`🎯 Objetivo: ${objetivo} → Tipo: ${tipoSesion}`);
console.log(`📅 Sesión ${numeroSesion} de ${sesionesSemanales}`);
console.log(`📋 Patrón: [${patron.join(', ')}]`);

let prompt = '';
let infoTipo = {};

if (tipoSesion === 'cardio') {
  infoTipo = {
    titulo: 'Cardio y Resistencia',
    enfoque: 'cardio'
  };

  // Los 4 sub-tipos de caminata se definen directamente en el prompt
  // No se necesita tabla ejercicios_cardio

  prompt = `Eres un experto en creación de programas de ejercicio cardiovascular para personas mayores y con movilidad limitada.

**PERFIL DEL USUARIO:**
- Nombre: ${usuario.nombre}
- Nivel físico: ${usuario.nivel_actual}
- Intensidad: ${usuario.intensidad_nivel}%${usuario.volumen_extra > 0 ? ` + ${usuario.volumen_extra}% volumen extra` : ''}
- Nivel de movilidad: ${nivelMovilidad}
- Limitaciones físicas: ${limitaciones}
- Objetivo principal: ${objetivo}

**TIPO DE SESIÓN A CREAR:**
🎯 **Cardio - Caminata adaptada**

${textoIntensidad} (Sesión ${numeroSesion} de ${sesionesSemanales})

**REGLA FUNDAMENTAL - SIN MATERIAL:**
⚠️ NUNCA propongas actividades que requieran equipamiento (bicicleta, escaleras, bandas, pesas, etc.)
Solo puedes proponer actividades que se puedan hacer en casa o al aire libre SIN NINGÚN MATERIAL.

**TIPOS DE CAMINATA DISPONIBLES (elige UNO como actividad principal):**

1. **Andar suave** - Caminar a ritmo cómodo y conversacional. Pasos cortos y relajados. Ideal para niveles bajos de intensidad o usuarios con limitaciones importantes.
   - Esfuerzo: 3-4/10
   - Duración típica: 15-25 minutos

2. **Andar moderado** - Caminar con paso firme y decidido, ritmo activo pero sostenible. Se puede mantener una conversación con frases cortas.
   - Esfuerzo: 5-6/10
   - Duración típica: 20-30 minutos

3. **Power walking** - Caminata enérgica con braceo activo y zancada amplia. Ritmo alto sin llegar a correr. Respiración más acelerada.
   - Esfuerzo: 6-7/10
   - Duración típica: 20-35 minutos

4. **Andar con cambios de intensidad** - Caminata con bloques alternados de ritmo fuerte y ritmo suave. SIN CORRER. Por ejemplo: 1-2 min rápido / 1-2 min suave. Incluye variaciones como cambios de dirección, elevar rodillas, o braceo intenso en los bloques fuertes.
   - Esfuerzo: alternando 7/10 y 4/10
   - Duración típica: 20-35 minutos

**GUÍA DE SELECCIÓN según nivel e intensidad:**
- Nivel iniciación + intensidad <50%: Andar suave
- Nivel iniciación + intensidad 50-70%: Andar moderado
- Nivel iniciación + intensidad >70%: Andar moderado o cambios de intensidad suaves
- Nivel intermedio + intensidad <50%: Andar moderado
- Nivel intermedio + intensidad 50-70%: Power walking
- Nivel intermedio + intensidad >70%: Power walking o cambios de intensidad
- Nivel avanzado + intensidad <60%: Power walking
- Nivel avanzado + intensidad >=60%: Cambios de intensidad

Esta guía es orientativa. Usa tu criterio profesional para adaptar según las limitaciones del usuario.

**TU TAREA:**
Crea un plan de caminata de 20-35 minutos que:

1. **Sea seguro** para el nivel ${usuario.nivel_actual} con limitaciones: ${limitaciones}
2. **NO requiera ningún material ni equipo** - solo el propio cuerpo
3. **Incluya calentamiento** (3-5 minutos de movilidad suave)
4. **ELIGE un tipo de caminata** de los 4 disponibles como actividad principal
5. **Proporcione guías claras de:**
   - Duración total y por fases
   - Intensidad (escala de esfuerzo 1-10)
   - Cómo debe sentirse el usuario (respiración, sensación corporal)
   - Señales de que debe parar o reducir intensidad

**IMPORTANTE - TEXTOS BREVES Y CLAROS:**
El usuario tiene 60-70 años y lee en el móvil. Todos los textos deben ser:
- Frases cortas y directas (máximo 15 palabras por punto)
- Formato lista con viñetas separadas por punto y coma (;), NO párrafos largos
- Sin repetir información entre campos
- Sin paréntesis explicativos innecesarios

**IMPORTANTE SOBRE LIMITACIONES:**
${limitaciones !== 'ninguna' ? `El usuario tiene limitaciones en: ${limitaciones}. Adapta la caminata para evitar estrés en estas áreas. Por ejemplo, si tiene problemas de rodilla, recomienda pasos más cortos y superficies llanas.` : 'No hay limitaciones específicas reportadas.'}

**FORMATO DE SALIDA:**
Devuelve ÚNICAMENTE un objeto JSON válido (sin markdown, sin explicaciones adicionales):

{
  "titulo": "Sesión ${numeroSesion}: Cardio - Caminata adaptada",
  "introduccion_personalizada": "Breve texto motivacional personalizado para ${usuario.nombre}",
  "enfoque": "cardio",
  "duracion_estimada": "20-35 minutos",
  "ejercicio_resistencia": {
    "nombre": "Nombre exacto del tipo de caminata elegido",
    "descripcion_adaptada": "1-2 frases: qué tipo de caminata es y para qué sirve",
    "duracion": "15-25 minutos",
    "protocolo_adaptado": "3-5 puntos breves separados por ;: ritmo; braceo; respiración; postura"
  },
  "ejercicio_intervalos": {
    "nombre": null,
    "descripcion_adaptada": "",
    "protocolo_adaptado": "",
    "incluir": false
  },
  "calentamiento_texto": "3-5 puntos breves del calentamiento, separados por punto y coma",
  "estructura_sesion": {
    "fases": [
      {
        "fase": "Calentamiento",
        "duracion": "3-5 minutos",
        "intensidad": "Baja (3-4/10)",
        "descripcion": "3-5 instrucciones breves separadas por ;"
      },
      {
        "fase": "Caminata principal",
        "duracion": "15-25 minutos",
        "intensidad": "Según tipo elegido",
        "descripcion": "3-5 instrucciones breves separadas por ;"
      },
      {
        "fase": "Enfriamiento",
        "duracion": "3-5 minutos",
        "intensidad": "Baja (3-4/10)",
        "descripcion": "3-5 instrucciones breves separadas por ;"
      }
    ]
  },
  "senales_de_alerta": [
    "Dolor en el pecho o dificultad para respirar",
    "Mareo o náuseas",
    "Dolor articular intenso"
  ],
  "consejos_seguridad": [
    "Lleva agua si sales a caminar",
    "Usa calzado cómodo y adecuado"
  ],
  "progresion_sugerida": "1-2 frases breves sobre cómo progresar"
}

**NOTA sobre "Andar con cambios de intensidad":**
Si eliges este tipo, la fase principal debe detallar los bloques de trabajo/descanso en la descripción. NO uses el campo ejercicio_intervalos (déjalo con incluir: false). Toda la información va en ejercicio_resistencia y en las fases de estructura_sesion.

**VALIDACIÓN:**
- SOLO devuelve el JSON, nada más
- El enfoque DEBE ser: "cardio"
- El nombre en ejercicio_resistencia DEBE ser uno de: "Andar suave", "Andar moderado", "Power walking", "Andar con cambios de intensidad"
- ejercicio_intervalos.incluir DEBE ser false siempre
- Adapta la caminata a las limitaciones: ${limitaciones}`;

} else {
  infoTipo = {
    titulo: 'Fuerza Funcional',
    enfoque: 'fuerza'
  };

  const ejerciciosFiltrados = ejerciciosFuerza.slice(0, 50);
  // Guardar mapa para enriquecer respuesta después
  const mapaEjercicios = {};
  ejerciciosFiltrados.forEach(e => {
    mapaEjercicios[e.json.nombre_archivo] = {
      instrucciones_clave: e.json.instrucciones_clave || [],
      precauciones: e.json.precauciones || []
    };
  });
  const listaEjercicios = ejerciciosFiltrados.map((e, idx) => {
    return `${idx + 1}. [ARCHIVO: ${e.json.nombre_archivo}] ${e.json.nombre_espanol} (${e.json.nivel}) - ${e.json.descripcion_corta}`;
  }).join('\n');

  // Historial de ejercicios recientes
  let historialTexto = '';
  try {
    const histRaw = usuario.historial_ejercicios_fuerza;
    const historial = typeof histRaw === 'string' ? JSON.parse(histRaw) : histRaw;
    if (historial && historial.length > 0) {
      const sesionesHist = historial.map((h, i) => {
        const ejercicios = Array.isArray(h) ? h : (h.ejercicios || []);
        return `- Hace ${i + 1} sesion(es): ${ejercicios.join(', ')}`;
      });
      historialTexto = `\n\n**EJERCICIOS USADOS RECIENTEMENTE (EVITAR REPETIR):**\n${sesionesHist.join('\n')}\nElige ejercicios DIFERENTES. Al menos el 70% deben ser distintos a los de las últimas sesiones.`;
    }
  } catch(e) { console.log('No se pudo parsear historial:', e.message); }

  console.log(`🎯 Enviando ${ejerciciosFiltrados.length} ejercicios de fuerza`);

  prompt = `Eres un experto en creación de programas de ejercicio de fuerza para personas mayores y con movilidad limitada.

**PERFIL DEL USUARIO:**
- Nombre: ${usuario.nombre}
- Nivel físico: ${usuario.nivel_actual}
- Intensidad: ${usuario.intensidad_nivel}%${usuario.volumen_extra > 0 ? ` + ${usuario.volumen_extra}% volumen extra` : ''}
- Nivel de movilidad: ${nivelMovilidad}
- Limitaciones físicas: ${limitaciones}
- Objetivo principal: ${objetivo}

**TIPO DE SESIÓN A CREAR:**
🎯 **Fuerza Funcional**

${textoIntensidad} (Sesión ${numeroSesion} de ${sesionesSemanales})

Enfoque: Fortalecer músculos principales del cuerpo con peso corporal. Incluye trabajo de equilibrio (ejercicios unilaterales).

**EJERCICIOS DISPONIBLES:**
${listaEjercicios}${historialTexto}

**TU TAREA:**
Crea una sesión de fuerza de 25-30 minutos que:

1. **Calentamiento (2 ejercicios):** SIEMPRE ejercicios de movilidad articular y estiramientos dinámicos
2. **Trabajo Principal (4-6 ejercicios):** Ejercicios de fuerza que trabajen diferentes áreas del cuerpo

**REGLAS IMPORTANTES:**
- El calentamiento DEBE ser de movilidad (preparación articular)
- Balancea las áreas: piernas, core, brazos, equilibrio
- Adapta repeticiones al nivel ${usuario.nivel_actual}
- Respeta limitaciones: ${limitaciones}
- SIEMPRE incluye el campo 'descanso' en cada ejercicio del trabajo_principal (ej: '45 segundos entre series')
- La introducción debe explicar por qué esta sesión es importante para ${usuario.nombre}
- VARIEDAD: Explora TODA la lista de ejercicios disponibles. No te limites siempre a los mismos ejercicios. Cada sesión debe ser diferente, eligiendo combinaciones distintas para mantener la motivación del usuario

**FORMATO DE SALIDA:**
Devuelve ÚNICAMENTE un JSON válido:

{
  "titulo": "Sesión ${numeroSesion}: Fuerza Funcional - Nivel ${usuario.nivel_actual}",
  "introduccion_personalizada": "Mensaje motivador para ${usuario.nombre}",
  "enfoque": "fuerza",
  "duracion_estimada": "25-30 minutos",
  "calentamiento": [
    {"nombre_archivo": "archivo.mov", "nombre_espanol": "Nombre", "repeticiones": "10 reps", "duracion_aprox": "2 min"}
  ],
  "trabajo_principal": [
    {"nombre_archivo": "archivo.mov", "nombre_espanol": "Nombre", "repeticiones": "3x10", "descanso": "45 seg", "duracion_aprox": "4 min"}
  ]
}

**VALIDACIÓN:**
- SOLO JSON
- nombre_archivo: EXACTAMENTE el valor [ARCHIVO: xxx.mov] de la lista
- NO incluyas instrucciones_clave ni precauciones (se añaden automáticamente)
- Calentamiento = movilidad, Trabajo principal = fuerza
- UNILATERALES: Si incluyes Derecha, incluye Izquierda consecutivamente`;
}

return {
  json: {
    prompt: prompt,
    user_id: usuario.id,
    user_nombre: usuario.nombre,
    user_email: usuario.email,
    semana_actual: usuario.semana_actual,
    sesiones_objetivo: usuario.sesiones_objetivo_semana,
    tipo_sesion: tipoSesion,
    numero_sesion: numeroSesion,
    sesion: infoTipo,
    mapaEjercicios: typeof mapaEjercicios !== 'undefined' ? mapaEjercicios : {}
  }
};

// Parsear respuesta de Claude
const datosUsuario = $node["Preparar Prompt Claude"].json;
const respuestaClaude = $json;

console.log('🔍 Parseando respuesta de Claude...');

// Extraer el contenido del mensaje
let mensajeTexto = respuestaClaude.content[0].text;
console.log('📝 Texto recibido (primeros 200 chars):', mensajeTexto.substring(0, 200));

// Limpiar markdown code blocks si existen (```json ... ```)
if (mensajeTexto.includes('```')) {
  console.log('🧹 Limpiando bloques de markdown...');
  // Extraer contenido entre ```json y ``` o entre ``` y ```
  const match = mensajeTexto.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    mensajeTexto = match[1].trim();
    console.log('✅ Markdown removido');
  }
}

// Parsear JSON
let sesionGenerada;
try {
  sesionGenerada = JSON.parse(mensajeTexto);
  console.log('✅ JSON parseado correctamente');
  console.log('🎯 Enfoque:', sesionGenerada.enfoque);
} catch (error) {
  console.error('❌ Error al parsear JSON:', error.message);
  console.error('📄 Texto que intentó parsear:', mensajeTexto.substring(0, 500));
  throw new Error(`No se pudo parsear la respuesta de Claude: ${error.message}`);
}

// Validación básica
if (!sesionGenerada.enfoque || !sesionGenerada.titulo) {
  throw new Error('La sesión generada no tiene los campos requeridos');
}

// Verificar que el tipo coincida
if (sesionGenerada.enfoque !== datosUsuario.tipo_sesion) {
  console.warn(`⚠️ Tipo esperado: ${datosUsuario.tipo_sesion}, recibido: ${sesionGenerada.enfoque}`);
}

// Enriquecer ejercicios con instrucciones_clave y precauciones desde BD
// Construir mapa de instrucciones desde nodo Ejercicios Disponibles
const mapa = {};
try {
  const ejercicios = $('Obtener Ejercicios Disponibles').all();
  ejercicios.forEach(e => {
    mapa[e.json.nombre_archivo] = {
      instrucciones_clave: e.json.instrucciones_clave || [],
      precauciones: e.json.precauciones || []
    };
  });
  console.log('📚 Mapa de ejercicios cargado:', Object.keys(mapa).length, 'ejercicios');
} catch(e) { console.log('⚠️ No se pudo cargar mapa de ejercicios:', e.message); }

function enriquecerEjercicios(lista) {
  if (!Array.isArray(lista)) return lista;
  return lista.map(ej => {
    const datos = mapa[ej.nombre_archivo] || {};
    return {
      ...ej,
      instrucciones_clave: datos.instrucciones_clave || ej.instrucciones_clave || [],
      precauciones: datos.precauciones || ej.precauciones || []
    };
  });
}

if (sesionGenerada.calentamiento) {
  sesionGenerada.calentamiento = enriquecerEjercicios(sesionGenerada.calentamiento);
}
if (sesionGenerada.trabajo_principal) {
  sesionGenerada.trabajo_principal = enriquecerEjercicios(sesionGenerada.trabajo_principal);
}

return {
  json: {
    ...datosUsuario,
    sesion: sesionGenerada,
    tokens_usados: respuestaClaude.usage
  }
};

